package com.samudhra.certificates.controller;
import com.samudhra.certificates.dto.ApiResponse; import com.samudhra.certificates.entity.Student; import com.samudhra.certificates.repository.StudentRepository; import com.samudhra.certificates.service.CurrentUserService; import org.springframework.data.domain.*; import org.springframework.web.bind.annotation.*; import java.time.LocalDate; import java.util.*;
@RestController @RequestMapping("/api/students") public class StudentController {private final StudentRepository students;private final CurrentUserService current;public StudentController(StudentRepository s,CurrentUserService c){students=s;current=c;} @GetMapping public ApiResponse<?> list(@RequestParam(defaultValue="")String search,@RequestParam(defaultValue="0")int page,@RequestParam(defaultValue="20")int size){return ApiResponse.ok(students.findByOrganizationIdAndNameContainingIgnoreCaseOrOrganizationIdAndRegisterNumberContainingIgnoreCase(current.organization().getId(),search,current.organization().getId(),search,PageRequest.of(page,Math.min(size,100))).map(this::view));}@PostMapping public ApiResponse<?> create(@RequestBody Map<String,Object>b){Student s=new Student();s.setOrganization(current.organization());apply(s,b);return ApiResponse.ok(view(students.save(s)));}@PutMapping("/{id}") public ApiResponse<?> update(@PathVariable String id,@RequestBody Map<String,Object>b){Student s=owned(id);apply(s,b);return ApiResponse.ok(view(students.save(s)));}@DeleteMapping("/{id}") public void delete(@PathVariable String id){students.delete(owned(id));}private Student owned(String id){Student s=students.findById(id).orElseThrow(()->new NoSuchElementException("Student not found"));if(!s.getOrganization().getId().equals(current.organization().getId()))throw new NoSuchElementException("Student not found");return s;}private void apply(Student s,Map<String,Object>b){s.setName((String)b.getOrDefault("name",s.getName()));s.setRegisterNumber((String)b.getOrDefault("registerNumber",s.getRegisterNumber()));s.setStudentType((String)b.get("studentType"));s.setCollege((String)b.get("college"));s.setDepartment((String)b.get("department"));s.setCourse((String)b.get("course"));s.setEmail((String)b.get("email"));s.setPhone((String)b.get("phone"));s.setInternshipTitle((String)b.get("internshipTitle"));s.setDuration((String)b.get("duration"));s.setStatus((String)b.getOrDefault("status","ACTIVE"));if(b.get("startDate")!=null&&!String.valueOf(b.get("startDate")).trim().isEmpty())s.setStartDate(LocalDate.parse((String)b.get("startDate")));else s.setStartDate(null);if(b.get("endDate")!=null&&!String.valueOf(b.get("endDate")).trim().isEmpty())s.setEndDate(LocalDate.parse((String)b.get("endDate")));else s.setEndDate(null);}private Map<String,Object> view(Student s){Map<String,Object>m=new LinkedHashMap<>();m.put("id",s.getId());m.put("name",s.getName());m.put("registerNumber",s.getRegisterNumber());m.put("studentType",s.getStudentType());m.put("college",s.getCollege());m.put("department",s.getDepartment());m.put("course",s.getCourse());m.put("email",s.getEmail());m.put("phone",s.getPhone());m.put("internshipTitle",s.getInternshipTitle());m.put("duration",s.getDuration());m.put("startDate",s.getStartDate());m.put("endDate",s.getEndDate());m.put("status",s.getStatus());m.put("photo",s.getPhotoUrl());return m;}}
